declare module "rwsdk/worker" {
  interface DefaultAppContext {
    user?: {
      id: string;
      role: "admin" | "member" | "guest";
    };
    requestId?: string;
  }
}

import { RouteMiddleware } from "rwsdk/router";

export const appContextMiddleware = (): RouteMiddleware => ({ ctx, request, response }) => {
  // Generate a unique request ID
  const requestId = crypto.randomUUID();
  ctx.requestId = requestId;

  // Set X-Request-Id response header
  response.headers.set("X-Request-Id", requestId);

  // Populate ctx.user from request headers if X-User-Id is present
  const userId = request.headers.get("X-User-Id");
  if (userId) {
    const rawRole = request.headers.get("X-User-Role");
    const role =
      rawRole === "admin" || rawRole === "member" ? rawRole : "guest";
    ctx.user = { id: userId, role };
  }
};

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { appContextMiddleware } from "@/app/middleware";
import { Home } from "@/app/pages/home";

export type AppContext = {
  user?: {
    id: string;
    role: "admin" | "member" | "guest";
  };
  requestId?: string;
};

export default defineApp([
  setCommonHeaders(),
  appContextMiddleware(),
  route("/me", ({ ctx }) => {
    return new Response(
      JSON.stringify({ user: ctx.user ?? null, requestId: ctx.requestId }),
      {
        headers: {
          "Content-Type": "application/json",
          "X-Request-Id": ctx.requestId ?? "",
        },
      },
    );
  }),
  route("/me/role", ({ ctx }) => {
    const role = ctx.user?.role ?? "anonymous";
    return new Response(role, {
      headers: {
        "Content-Type": "text/plain",
        "X-Request-Id": ctx.requestId ?? "",
      },
    });
  }),
  render(Document, [route("/", Home)]),
]);
